// Persistence key for NSE database (client-side)
const NSE_DB_KEY = 'tradelog_nse_db_v1';

// Merge priority: nseDb.js (full, 2000+ stocks) > localStorage > MINIMAL_NSE_DB
function initNseDb() {
  // Start with minimal hardcoded list
  let base = [...MINIMAL_NSE_DB];
  // Overlay with full DB from nseDb.js if available (generated at build time)
  if (_NSE_FULL_DB && _NSE_FULL_DB.length > 0) {
    const map = new Map(_NSE_FULL_DB.map(e => [e.sym, e]));
    MINIMAL_NSE_DB.forEach(e => { if (!map.has(e.sym)) map.set(e.sym, e); });
    base = Array.from(map.values());
  }
  // Overlay with any user-added symbols from localStorage
  try {
    const saved = JSON.parse(window.localStorage.getItem(NSE_DB_KEY) || '[]');
    if (saved.length > 0) {
      const map = new Map(base.map(e => [e.sym, e]));
      saved.forEach(e => { if (e.sym && !map.has(e.sym)) map.set(e.sym, e); });
      base = Array.from(map.values());
    }
  } catch(e) {}
  return base;
}

function nseDbSave(db){
  try{ if(typeof window!=='undefined' && window.localStorage){ window.localStorage.setItem(NSE_DB_KEY, JSON.stringify(db)); }}catch(e){}
}

function nseDbLoad(){
  try{
    if(typeof window==='undefined' || !window.localStorage) return null;
    const t=window.localStorage.getItem(NSE_DB_KEY);
    if(!t) return null;
    const parsed=JSON.parse(t);
    if(Array.isArray(parsed)) return parsed;
  }catch(e){}
  return null;
}

// Initialize NSE_DB — priority: nseDb.js (full 2000+) > localStorage > MINIMAL_NSE_DB
NSE_DB = typeof window !== 'undefined' ? initNseDb() : [...MINIMAL_NSE_DB];
if (typeof window !== 'undefined') window.NSE_DB = NSE_DB;
console.info('NSE_DB ready — entries:', NSE_DB.length, _NSE_FULL_DB?.length > 0 ? '(from nseDb.js)' : '(fallback)');

// NSE CSV (archives.nseindia.com/content/equities/EQUITY_L.csv) is blocked by
// Akamai in all browser environments — proxying it just returns HTML.
// Instead we do on-demand name lookups via Yahoo Finance search (same /yf proxy
// already used for live prices). Results are cached in NSE_DB per-session.

const YF_NAME_CACHE = new Map(); // sym -> name

async function lookupStockName(sym) {
  if (!sym) return '';
  const upper = sym.toUpperCase();
  const local = NSE_DB.find(e => e.sym === upper);
  if (local?.name) return local.name;
  if (YF_NAME_CACHE.has(upper)) return YF_NAME_CACHE.get(upper);
  try {
    const url = yfSearchUrl(upper);
    const r = await fetch(url, { signal: AbortSignal.timeout(5000) });
    if (r.ok) {
      const d = await r.json();
      const hit = d?.quotes?.[0];
      if (hit?.shortname || hit?.longname) {
        const name = hit.shortname || hit.longname;
        YF_NAME_CACHE.set(upper, name);
        NSE_DB = [{ sym: upper, name, sector: hit.sector || '' }, ...NSE_DB.filter(e => e.sym !== upper)];
        nseDbSave(NSE_DB);
        return name;
      }
    }
  } catch (e) { /* best-effort, silent */ }
  return upper;
}

if (typeof window !== 'undefined') window.NSE_DB = NSE_DB;

