// ── Auth Page ─────────────────────────────────────────────────────────────────
/* ── Shared field style for auth forms ─────────────────────────────────────── */
const AUTH_FIELD = { marginBottom:16 };
const AUTH_LABEL = { display:'block',fontSize:11,color:'var(--txt3)',fontFamily:"'DM Mono'",letterSpacing:'.04em',marginBottom:6,textTransform:'uppercase' };

/* ── Login Form — own component so inputs never remount on parent re-render ── */
function LoginForm({ onLogin, onError, setLoading, loading, cloudSyncEnabled }){
  const emailRef = useRef('');
  const passRef  = useRef('');
  const [showPw, setShowPw] = useState(false);
  const userCount = Object.keys(usersLoad()).length;

  const submit = async e => {
    e.preventDefault();
    const emailOrUser = emailRef.current.value.trim();
    const password    = passRef.current.value;
    if(!emailOrUser || !password){ onError('Enter both email/username and password.'); return; }
    setLoading(true); onError('');
    if(cloudSyncEnabled && supabase){
      // Supabase: login is always by email
      const { data, error:err } = await supabase.auth.signInWithPassword({ email: emailOrUser, password });
      if(err){ onError(err.message); setLoading(false); return; }
      // Read display name from user_metadata (set at signup) — avoids separate profiles query
      const meta = data.user.user_metadata || {};
      const session = {
        id:       data.user.id,
        username: meta.username || emailOrUser.split('@')[0],
        name:     meta.full_name || meta.username || emailOrUser.split('@')[0],
      };
      sessionSave(session);
      onLogin(session);
    } else {
      const res = await loginUserLocal({ username: emailOrUser, password });
      if(!res.ok){ onError(res.error); setLoading(false); return; }
      const session = { id: res.username, username:res.username, name:res.name };
      sessionSave(session);
      onLogin(session);
    }
    setLoading(false);
  };

  const btnStyle = {width:'100%',padding:'13px',borderRadius:12,border:'none',background:'var(--accent)',color:'#111',fontSize:14,fontWeight:700,cursor:loading?'not-allowed':'pointer',opacity:loading?0.7:1,marginTop:4,transition:'opacity .2s'};
  const inStyle  = {paddingRight:42};

  return (
    <form onSubmit={submit}>
      <div style={AUTH_FIELD}>
        <label style={AUTH_LABEL}>{cloudSyncEnabled ? 'Email' : 'Username'}</label>
        <input ref={emailRef} type={cloudSyncEnabled?'email':'text'} placeholder={cloudSyncEnabled?'your@email.com':'Enter your username'} autoComplete={cloudSyncEnabled?'email':'username'} defaultValue=""/>
      </div>
      <div style={AUTH_FIELD}>
        <label style={AUTH_LABEL}>Password</label>
        <div style={{position:'relative'}}>
          <input ref={passRef} type={showPw?'text':'password'} placeholder="Enter your password" autoComplete="current-password" defaultValue="" style={inStyle}/>
          <button type="button" onClick={()=>setShowPw(s=>!s)} style={{position:'absolute',right:10,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',cursor:'pointer',color:'var(--txt3)',fontSize:13,padding:4}}>{showPw?'🙈':'👁'}</button>
        </div>
      </div>
      <button type="submit" disabled={loading} style={btnStyle}>{loading?'Signing in…':'Sign In →'}</button>
      {!cloudSyncEnabled && <div style={{marginTop:12,textAlign:'center',fontSize:11,color:'var(--txt4)',fontFamily:"'DM Mono'"}}>{userCount} account{userCount!==1?'s':''} · local only</div>}
    </form>
  );
}

/* ── Signup Form ─────────────────────────────────────────────────────────────── */
function SignupForm({ onSuccess, onError, setLoading, loading, cloudSyncEnabled }){
  const nameRef    = useRef();
  const usernameRef= useRef();
  const emailRef   = useRef();
  const passRef    = useRef();
  const confirmRef = useRef();
  const [showPw, setShowPw] = useState(false);

  const submit = async e => {
    e.preventDefault();
    const name     = nameRef.current.value.trim();
    const username = usernameRef.current.value.trim().toLowerCase();
    const email    = emailRef.current.value.trim();
    const password = passRef.current.value;
    const confirm  = confirmRef.current.value;
    if(password !== confirm){ onError('Passwords do not match.'); return; }
    if(!name || !username || !password){ onError('All fields are required.'); return; }
    if(cloudSyncEnabled && !email){ onError('Email is required for cloud sync.'); return; }
    setLoading(true); onError('');
    if(cloudSyncEnabled && supabase){
      const { data, error:err } = await supabase.auth.signUp({
        email, password,
        options:{ data:{ username, full_name:name } }
      });
      if(err){ onError(err.message); setLoading(false); return; }
      // Profile auto-created by handle_new_user DB trigger — no client-side insert needed.
      // If email confirmation is disabled in Supabase, data.session will be set immediately.
      if(data.user && !data.session){
        onSuccess('Account created! Check your email to confirm, then sign in.');
      } else {
        onSuccess('Account created! You can now sign in.');
      }
    } else {
      const res = await registerUserLocal({ username, name, email, password });
      if(!res.ok){ onError(res.error); setLoading(false); return; }
      onSuccess('Account created! You can now sign in.');
    }
    setLoading(false);
  };

  const inPw = {paddingRight:42};
  const btnStyle = {width:'100%',padding:'13px',borderRadius:12,border:'none',background:'var(--accent)',color:'#111',fontSize:14,fontWeight:700,cursor:loading?'not-allowed':'pointer',opacity:loading?0.7:1,marginTop:4};

  return (
    <form onSubmit={submit}>
      <div style={AUTH_FIELD}><label style={AUTH_LABEL}>Full Name</label><input ref={nameRef} type="text" placeholder="Your full name" autoComplete="name" defaultValue=""/></div>
      <div style={AUTH_FIELD}><label style={AUTH_LABEL}>Username</label><input ref={usernameRef} type="text" placeholder="Choose a username (min 3 chars)" autoComplete="username" defaultValue=""/></div>
      <div style={AUTH_FIELD}><label style={AUTH_LABEL}>Email {cloudSyncEnabled?'(required)':'(optional)'}</label><input ref={emailRef} type="email" placeholder="your@email.com" autoComplete="email" defaultValue=""/></div>
      <div style={AUTH_FIELD}>
        <label style={AUTH_LABEL}>Password (min 6 chars)</label>
        <div style={{position:'relative'}}>
          <input ref={passRef} type={showPw?'text':'password'} placeholder="Choose a password" autoComplete="new-password" defaultValue="" style={inPw}/>
          <button type="button" onClick={()=>setShowPw(s=>!s)} style={{position:'absolute',right:10,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',cursor:'pointer',color:'var(--txt3)',fontSize:13,padding:4}}>{showPw?'🙈':'👁'}</button>
        </div>
      </div>
      <div style={AUTH_FIELD}><label style={AUTH_LABEL}>Confirm Password</label><input ref={confirmRef} type={showPw?'text':'password'} placeholder="Repeat password" autoComplete="new-password" defaultValue=""/></div>
      <button type="submit" disabled={loading} style={btnStyle}>{loading?'Creating account…':'Create Account →'}</button>
    </form>
  );
}

/* ── Auth Page shell ─────────────────────────────────────────────────────────── */
function AuthPage({ onLogin, cloudSyncEnabled }){
  const [mode, setMode]     = useState('login');
  const [loading, setLoading] = useState(false);
  const [error, setError]   = useState('');
  const [success, setSuccess] = useState('');

  const switchMode = m => { setMode(m); setError(''); setSuccess(''); };

  return (
    <div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',padding:24,background:'var(--bg0)'}}>
      <div style={{position:'fixed',inset:0,zIndex:0,background:'radial-gradient(ellipse 80% 60% at 50% -10%, rgba(0,229,160,.07), transparent)',pointerEvents:'none'}}/>
      <div style={{position:'relative',zIndex:1,width:'100%',maxWidth:440}}>
        <div style={{textAlign:'center',marginBottom:32}}>
          <div style={{fontFamily:"'Syne'",fontSize:32,fontWeight:800,color:'var(--txt1)',letterSpacing:'-.03em'}}>Trade<span style={{color:'var(--accent)'}}>Log</span></div>
          <div style={{fontSize:13,color:'var(--txt3)',marginTop:4}}>Your personal trading journal</div>
          {cloudSyncEnabled && <div style={{marginTop:8,fontSize:11,color:'var(--accent)',fontFamily:"'DM Mono'",background:'rgba(0,229,160,.08)',display:'inline-block',padding:'3px 10px',borderRadius:20,border:'1px solid rgba(0,229,160,.2)'}}>☁ Cloud sync enabled</div>}
        </div>
        <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:24,padding:36,boxShadow:'0 40px 100px rgba(0,0,0,.5)'}}>
          <div style={{display:'flex',background:'var(--bg4)',borderRadius:12,padding:4,marginBottom:28,gap:4}}>
            {[{id:'login',label:'Sign In'},{id:'signup',label:'Create Account'}].map(t=>(
              <button key={t.id} onClick={()=>switchMode(t.id)} style={{flex:1,padding:'9px',borderRadius:9,border:'none',background:mode===t.id?'var(--accent)':'transparent',color:mode===t.id?'#111':'var(--txt3)',fontSize:13,fontWeight:mode===t.id?700:400,cursor:'pointer',transition:'all .2s'}}>{t.label}</button>
            ))}
          </div>
          {success && <div style={{marginBottom:16,padding:'10px 14px',borderRadius:10,background:'rgba(0,229,160,.1)',border:'1px solid rgba(0,229,160,.3)',color:'var(--accent)',fontSize:13}}>{success}</div>}
          {error   && <div style={{marginBottom:16,padding:'10px 14px',borderRadius:10,background:'rgba(255,92,92,.1)',border:'1px solid rgba(255,92,92,.3)',color:'var(--red)',fontSize:13}}>{error}</div>}
          {mode==='login'
            ? <LoginForm  onLogin={onLogin} onError={setError} setLoading={setLoading} loading={loading} cloudSyncEnabled={cloudSyncEnabled}/>
            : <SignupForm onSuccess={msg=>{setSuccess(msg);switchMode('login');}} onError={setError} setLoading={setLoading} loading={loading} cloudSyncEnabled={cloudSyncEnabled}/>
          }
        </div>
        <div style={{textAlign:'center',marginTop:18,fontSize:11,color:'var(--txt4)',fontFamily:"'DM Mono'"}}>
          {cloudSyncEnabled ? 'Data synced to cloud · Access from any device' : 'Data stored locally · No subscription required'}
        </div>
      </div>
    </div>
  );
}

/* ─── App Root ──────────────────────────────────────────────────────────────── */
export default function App(){
  // Legacy VITE_BACKEND_URL system removed — local browser storage is now the single source of truth.
  const [page, setPage]     = useState("dashboard");
  const [theme, setTheme]   = useState(()=>{
    try{
      const t = localStorage.getItem('tradelog_theme')||'dark';
      document.body.className = `theme-${t}`; // apply immediately, before first paint
      return t;
    }catch(e){ return 'dark'; }
  });
  const toggleTheme = () => setTheme(t=>{ const n=t==='dark'?'light':'dark'; try{ localStorage.setItem('tradelog_theme',n); }catch(e){} return n; });

  // Apply theme class to <body> so modals/portals rendered outside app-shell also get CSS vars
  useEffect(()=>{
    document.body.className = `theme-${theme}`;
  }, [theme]);
  const [user, setUser]             = useState(() => sessionLoad() || null);
  const [syncStatus, setSyncStatus] = useState('idle'); // 'idle'|'syncing'|'synced'|'offline'
  const [trades, setTrades]         = useState([]);     // ALWAYS starts empty — never read from localStorage
  const [tradesLoading, setTradesLoading] = useState(true);
  const [editing, setEditing] = useState(null);
  const [viewing, setViewing] = useState(null);
  const [toast, setToast]   = useState("");
  const [openPrices, setOpenPrices] = useState({});
  const [cloudSyncReady, setCloudSyncReady] = useState(false);

  useEffect(() => {
    let cancelled = false;
    if (!isSupabaseConfigured || !supabase) {
      setCloudSyncReady(false);
      return () => { cancelled = true; };
    }

    (async () => {
      const available = await canUseSupabaseAuth();
      if (!cancelled) setCloudSyncReady(available);
    })();

    return () => { cancelled = true; };
  }, []);

  const cloudSyncEnabled = isSupabaseConfigured && !!supabase && cloudSyncReady;

  // ── Load trades from local storage — the ONLY source of truth ──────────────
  const loadTradesFromSupabase = useCallback(async (session) => {
    if(!session) { setTrades([]); setTradesLoading(false); return; }
    setTradesLoading(true);
    setSyncStatus('syncing');
    const userId = session.id || session.username || 'guest';
    const storedTrades = await sbFetchTrades(userId);
    setTrades(storedTrades);
    setSyncStatus('offline');
    setTradesLoading(false);
  }, []);

  // Restore session on page load/refresh (any browser) and fetch fresh from Supabase
  useEffect(() => {
    const s = sessionLoad();
    if(s){ setUser(s); loadTradesFromSupabase(s); }
    else { setTradesLoading(false); }
  }, [loadTradesFromSupabase]);

  // Local-only sessions do not need a remote auth re-validation pass.
  useEffect(() => {
    if(cloudSyncEnabled) return;
    const cached = sessionLoad();
    if(!cached){ setUser(null); setTrades([]); }
  }, [cloudSyncEnabled]);

  const handleLogin = async session => {
    setUser(session);
    sessionSave(session);
    await loadTradesFromSupabase(session);
    setPage("dashboard");
  };

  const logout = async () => {
    sessionClear(); setUser(null); setTrades([]); setSyncStatus('idle'); setPage('dashboard');
  };

  const liveTradeMetrics = t => {
    if(t.status !== "open") return null;
    const price = openPrices[t.sym];
    if(price == null) return null;
    const gross = t.dir === "BUY" ? (price - t.entryPrice) * t.qty : (t.entryPrice - price) * t.qty;
    const net = gross - (t.brokerage || 0);
    const pct = t.entryPrice && t.qty ? (net / (t.entryPrice * t.qty)) * 100 : 0;
    return { price, gross, net, pct };
  };

  // Manual fetch — called only when user clicks "Fetch Live Prices" on Dashboard
  const [priceLoading, setPriceLoading] = useState(false);
  const [lastPriceFetch, setLastPriceFetch] = useState(null);
  const toastRef = useRef(null);

  const fetchLivePrices = useCallback(async () => {
    const openTrades = trades
      .filter(t => t.status === "open" && t.sym)
      .map(t => ({ sym: t.sym, ticker: t.ticker || (t.sym + '.NS') }));
    const seen = new Set();
    const unique = openTrades.filter(t => seen.has(t.sym) ? false : seen.add(t.sym));
    if(unique.length === 0) return;
    setPriceLoading(true);
    const fetched = await fetchBulkLTP(unique);
    const successCount = Object.keys(fetched).length;
    if(successCount > 0){
      setOpenPrices(prev => ({...prev, ...fetched}));
      setLastPriceFetch(new Date());
    } else if(successCount === 0 && Date.now() >= LTP_BACKOFF_UNTIL){
      // Only show feedback if not rate limited
      if(toastRef.current) toastRef.current(`✗ Could not fetch prices for ${unique.length} symbols`);
    } else if(Date.now() < LTP_BACKOFF_UNTIL){
      // Rate limited - show friendly message
      const remainingMin = Math.ceil((LTP_BACKOFF_UNTIL - Date.now()) / 60000);
      if(toastRef.current) toastRef.current(`⏳ Yahoo Finance rate limited — try again in ${remainingMin}m`);
    }
    setPriceLoading(false);
  }, [trades]);

  useEffect(() => {
    if (!user || !trades.some(t => t.status === 'open' && t.sym) || priceLoading || lastPriceFetch) return;
    fetchLivePrices();
  }, [user, trades, priceLoading, lastPriceFetch, fetchLivePrices]);

  const loginView = !user
    ? <AuthPage onLogin={handleLogin} cloudSyncEnabled={cloudSyncEnabled}/>
    : tradesLoading
      ? <div style={{minHeight:'100vh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:14,background:'var(--bg1)'}}>
          <div style={{fontFamily:"'Syne'",fontSize:24,fontWeight:800,color:'var(--txt1)'}}>Trade<span style={{color:'var(--accent)'}}>Log</span></div>
          <div style={{fontSize:12,color:'var(--txt3)',fontFamily:"'DM Mono'"}}>⟳ Loading your trades from the cloud…</div>
        </div>
      : null;

  // ── Toast helper ──
  const showToast = msg => { setToast(msg); setTimeout(()=>setToast(""), 2800); };
  useEffect(() => { toastRef.current = showToast; }, []);

  // ── Trade CRUD — written locally to browser storage with no subscription ───
  const saveUserTrades = async (updated, changedTrade=null, deletedId=null) => {
    setTrades(updated);   // optimistic UI update
    const storageUserId = user?.id || user?.username || 'guest';
    setSyncStatus('offline');
    try{
      if(deletedId) await sbDeleteTrade(storageUserId, deletedId);
      else if(changedTrade) await sbSaveTrade(storageUserId, changedTrade);
      else await sbSaveAllTrades(storageUserId, updated);
    }catch(e){
      showToast('✗ Could not save locally');
    }
  };

  const saveTrade = t => {
    const exists = trades.find(x => x.id === t.id);
    const updated = exists ? trades.map(x => x.id === t.id ? t : x) : [t, ...trades];
    saveUserTrades(updated, t);   // writes to localStorage cache + syncs to Supabase
    setEditing(null);
    setPage("journal");
    showToast(exists ? "✓ Trade updated" : "✓ Trade saved");
  };
  const deleteTrade = id => {
    const updated = trades.filter(t => t.id !== id);
    saveUserTrades(updated, null, id);   // also deletes from Supabase
    showToast("Trade deleted");
  };
  const startEdit = t => { setEditing(t); setPage("add"); };

  // ── Backup: export entire DB as JSON ──
  const exportJSON = () => {
    const blob = new Blob([JSON.stringify(trades, null, 2)], {type:"application/json"});
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `tradelog-backup-${new Date().toISOString().slice(0,10)}.json`;
    a.click();
    showToast("✓ Backup downloaded");
  };

  // ── Restore: import JSON backup ──
  const importJSON = e => {
    const file = e.target.files[0]; if(!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      try{
        const data = JSON.parse(ev.target.result);
        if(!Array.isArray(data)) throw new Error("Invalid");
        if(!confirm(`Import ${data.length} trades? This will replace your current data.`)) return;
        saveUserTrades(data);
        showToast(`✓ Imported ${data.length} trades`);
      }catch{ showToast("✗ Invalid backup file"); }
    };
    reader.readAsText(file);
    e.target.value = "";
  };

  // ── Restore: import CSV backup ──
  const importCSV = e => {
    const file = e.target.files[0]; if(!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      try{
        const text = ev.target.result;
        const lines = text.split(/\r?\n/).filter(l => l.trim());
        if(lines.length < 2) throw new Error('Invalid CSV file');
        const headers = parseCSVLine(lines[0]).map(h => h.trim());
        const normalize = str => String(str || '').trim().toLowerCase().replace(/[^a-z0-9]+/g, '');
        const rows = lines.slice(1).map(line => parseCSVLine(line));
        const parsed = rows.map((row, rowIndex) => {
          const item = headers.reduce((acc, key, idx) => {
            acc[normalize(key)] = row[idx] != null ? row[idx].trim() : "";
            return acc;
          }, {});
          const sym = (item.symbol || item.sym || item.ticker || item.stock || "").toUpperCase();
          if(!sym) return null;
          const dir = (item.dir || item.direction || "BUY").toUpperCase();
          const status = (item.status || "closed").toLowerCase() === "open" ? "open" : "closed";
          return {
            id: item.id ? Number(item.id) || Date.now() + rowIndex : Date.now() + rowIndex,
            sym,
            name: item.name || item.company || sym,
            sector: item.sector || "",
            dir: dir === "SELL" ? "SELL" : "BUY",
            status,
            entryDate: item.entrydate || item.date || "",
            exitDate: item.exitdate || "",
            entryPrice: parseFloat(item.entryprice || item.entry || item.ep || "") || 0,
            exitPrice: parseFloat(item.exitprice || item.exit || item.xp || "") || 0,
            qty: parseFloat(item.qty || item.quantity || item.qtyshares || item.quantityshares || "") || 0,
            brokerage: parseFloat(item.brokerage || item.brokers || item.fees || "") || 0,
            strategy: item.strategy || item.strat || "",
            timeframe: item.timeframe || item.tf || "",
            rating: Number(item.rating) || 0,
            emotions: item.emotions ? item.emotions.split(/[,;]+/).map(v=>v.trim()).filter(Boolean) : [],
            entryReason: item.entryreason || item.entrynotes || "",
            exitReason: item.exitreason || item.exitnotes || "",
            lessons: item.lessons || item.notes || "",
            tags: item.tags || "",
            screenshots: [],
            sl: parseFloat(item.sl || item.stoploss || "") || 0,
            target: parseFloat(item.target || item.tgt || "") || 0,
          };
        }).filter(Boolean);
        if(parsed.length === 0) throw new Error('No valid trades found');
        if(!confirm(`Import ${parsed.length} trades? This will replace your current data.`)) return;
        saveUserTrades(parsed);
        showToast(`✓ Imported ${parsed.length} CSV trades`);
      }catch(err){ console.warn(err); showToast("✗ Invalid CSV file"); }
    };
    reader.readAsText(file);
    e.target.value = "";
  };

  // ── Reset to demo data ──
  const resetDemo = () => {
    if(!confirm("Reset to demo data? Your current trades will be lost.")) return;
    saveUserTrades(SEED);
    showToast("✓ Reset to demo data");
  };

  const importRef = useRef();
  const csvImportRef = useRef();

  return <>
    <GF/>
    <style>{`
      /* ════════════════════════════════════════════════════════
         TRADELOG — Theme System
         Dark: deep navy-black (much richer than before)
         Light: clean white with warm grey hierarchy
      ════════════════════════════════════════════════════════ */

      body.theme-dark {
        /* Surfaces — layered navy-black, not flat grey */
        --bg0:    #080810;   /* true base, used for overlay */
        --bg1:    #0b0b14;   /* page background             */
        --bg2:    #10101e;   /* card surface                */
        --bg3:    #0d0d1a;   /* sidebar                     */
        --bg4:    #16162a;   /* elevated / hover            */
        --bg5:    #1c1c30;   /* input background            */

        /* Borders */
        --border:  #1e1e35;
        --border2: #28283f;

        /* Text */
        --txt1:  #eeeef8;    /* primary — slightly blue-white */
        --txt2:  #9898b8;    /* secondary                     */
        --txt3:  #55556a;    /* muted                         */
        --txt4:  #35354a;    /* very muted                    */

        /* Brand */
        --accent:  #00e5a0;
        --accent2: #00b87a;
        --red:     #ff5c5c;
        --amber:   #ffb340;
        --blue:    #5b9eff;

        /* Util */
        --shadow:  rgba(0,0,0,.6);
        --modal-bg:rgba(4,4,12,.88);
        --pill-bg: #1c1c30;
      }

      body.theme-light {
        --bg0:    #e2e2ec;
        --bg1:    #f0f0f6;
        --bg2:    #ffffff;
        --bg3:    #f7f7fb;
        --bg4:    #eaeaf2;
        --bg5:    #e8e8f0;
        --border:  #dcdce8;
        --border2: #c8c8d8;
        --txt1:  #111120;
        --txt2:  #44445a;
        --txt3:  #888898;
        --txt4:  #bbbbcc;
        --accent:  #008a60;
        --accent2: #006e4c;
        --red:     #d93030;
        --amber:   #c07800;
        --blue:    #1a5fd4;
        --shadow:  rgba(0,0,0,.1);
        --modal-bg:rgba(0,0,0,.5);
        --pill-bg: #eaeaf2;
      }

      /* ── Fallback vars (before JS applies theme class) ── */
      :root {
        --bg0:#080810;--bg1:#0b0b14;--bg2:#10101e;--bg3:#0d0d1a;
        --bg4:#16162a;--bg5:#1c1c30;
        --border:#1e1e35;--border2:#28283f;
        --txt1:#eeeef8;--txt2:#9898b8;--txt3:#55556a;--txt4:#35354a;
        --accent:#00e5a0;--accent2:#00b87a;--red:#ff5c5c;--amber:#ffb340;--blue:#5b9eff;
        --shadow:rgba(0,0,0,.6);--modal-bg:rgba(4,4,12,.88);--pill-bg:#1c1c30;
      }

      /* ── Reset ─────────────────────────────────────────── */
      *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
      html{-webkit-text-size-adjust:100%;}
      body{
        background:var(--bg1);color:var(--txt1);
        font-family:'DM Sans',sans-serif;overflow-x:hidden;
        transition:background .25s,color .25s;
      }
      input,select,textarea,button{font-family:'DM Sans',sans-serif;}
      input,select,textarea{
        background:var(--bg5);color:var(--txt1);
        border:1px solid var(--border2);border-radius:9px;
        padding:9px 13px;font-size:13px;width:100%;
        outline:none;transition:border .15s,background .2s;
      }
      input:focus,select:focus,textarea:focus{
        border-color:var(--accent);
        box-shadow:0 0 0 3px rgba(0,229,160,.08);
      }
      select option{background:var(--bg2);color:var(--txt1);}
      textarea{resize:vertical;min-height:70px;}
      a{color:var(--accent);}

      /* ── Layout ────────────────────────────────────────── */
      .app-shell{display:flex;min-height:100vh;background:var(--bg1);}

      .app-sidebar{
        position:fixed;top:0;left:0;width:224px;height:100vh;
        background:var(--bg3);
        border-right:1px solid var(--border);
        display:flex;flex-direction:column;
        padding:24px 0;z-index:100;overflow-y:auto;
        transition:background .25s;
      }

      .app-content{
        flex:1;margin-left:224px;
        padding:30px 36px;
        min-height:100vh;overflow-y:auto;
      }

      /* ── Sidebar nav active ─────────────────────────────── */
      .nav-item-active{
        background:rgba(0,229,160,.09) !important;
        color:var(--accent) !important;
      }
      .theme-light .nav-item-active{
        background:rgba(0,138,96,.1) !important;
      }

      /* ── Cards ─────────────────────────────────────────── */
      .card{
        background:var(--bg2);
        border:1px solid var(--border);
        border-radius:16px;
      }
      .stat-pill{
        background:var(--pill-bg);
        border:1px solid var(--border);
        border-radius:12px;
        padding:14px;
        text-align:center;
      }

      /* ── Modal overlay ──────────────────────────────────── */
      .modal-overlay{
        position:fixed;inset:0;z-index:999;
        background:var(--modal-bg);
        display:flex;align-items:center;justify-content:center;
        padding:20px;
        backdrop-filter:blur(4px);
      }
      .modal-box{
        background:var(--bg2);
        border:1px solid var(--border2);
        border-radius:20px;
        width:100%;max-width:580px;
        max-height:90vh;overflow-y:auto;
        padding:28px 32px;
        box-shadow:0 40px 100px var(--shadow);
      }

      /* ── Table ─────────────────────────────────────────── */
      .table-scroll{width:100%;overflow-x:auto;-webkit-overflow-scrolling:touch;}
      .table-scroll table{min-width:660px;}
      .table-scroll tr:hover td{background:var(--bg4) !important;}

      /* ── Mobile nav ─────────────────────────────────────── */
      .mobile-nav{
        display:none;position:fixed;bottom:0;left:0;right:0;z-index:200;
        background:var(--bg3);border-top:1px solid var(--border);
        padding:6px 0 calc(6px + env(safe-area-inset-bottom));
        flex-direction:row;justify-content:space-around;align-items:center;
      }
      .mobile-nav button{
        background:none;border:none;color:var(--txt3);font-size:10px;
        cursor:pointer;display:flex;flex-direction:column;align-items:center;
        gap:2px;padding:4px 10px;min-width:50px;
      }
      .mobile-nav button.active{color:var(--accent);}
      .mobile-nav button span.icon{font-size:19px;line-height:1;}

      /* ── Scrollbar ──────────────────────────────────────── */
      ::-webkit-scrollbar{width:4px;height:4px;}
      ::-webkit-scrollbar-track{background:transparent;}
      ::-webkit-scrollbar-thumb{background:var(--border2);border-radius:2px;}

      /* ── Responsive ─────────────────────────────────────── */
      @media (max-width:980px){
        .app-sidebar{display:none;}
        .app-content{margin-left:0;padding:18px 14px;padding-bottom:80px;}
        .mobile-nav{display:flex;}
      }
      @media (max-width:600px){
        .app-content{padding:12px 10px;padding-bottom:80px;}
        input,select,textarea{font-size:16px;}
        .modal-box{padding:20px 18px;border-radius:16px 16px 0 0;max-height:95vh;}
        .modal-overlay{align-items:flex-end;padding:0;}
      }

      /* ── Utility ────────────────────────────────────────── */
      .divider{border:none;border-top:1px solid var(--border);margin:16px 0;}
      @keyframes spin{to{transform:rotate(360deg);}}
    `}</style>

    {loginView || (
      <>
        <div className="app-shell">
          <Sidebar page={page} setPage={p=>{if(p!="add")setEditing(null);setPage(p);}}
            tradeCount={trades.length}
            onExport={exportJSON}
            onImport={()=>importRef.current.click()}
            onImportCSV={()=>csvImportRef.current.click()}
            onReset={resetDemo}
            user={user?.name||user?.username||user}
            onLogout={logout}
            theme={theme} toggleTheme={toggleTheme} syncStatus={syncStatus}
          />
          <input ref={importRef} type="file" accept=".json" style={{display:"none"}} onChange={importJSON}/>
          <input ref={csvImportRef} type="file" accept=".csv" style={{display:"none"}} onChange={importCSV}/>

          <div className="app-content">
            {page==="dashboard" && <Dashboard trades={trades} setPage={setPage} setView={setViewing} openPrices={openPrices} onFetchPrices={fetchLivePrices} priceLoading={priceLoading} lastPriceFetch={lastPriceFetch}/>}
            {page==="journal"   && <Journal trades={trades} onEdit={startEdit} onDelete={deleteTrade} setView={setViewing} openPrices={openPrices}/>}
            {page==="add"       && <AddTrade initial={editing} onSave={saveTrade} onCancel={()=>{setEditing(null);setPage("journal");}}/>}
            {page==="alerts"    && <AlertsPage trades={trades} userId={user?.id}/>}
            {page==="calendar"  && <TradeCalendar trades={trades}/>}
            {page==="goals"     && <GoalsTracker trades={trades} username={user?.username} userId={user?.id}/>}
            {page==="dailyjournal" && <DailyJournal trades={trades} username={user?.username} userId={user?.id}/>}
            {page==="stickies"    && <StickyNotesPage username={user?.username} userId={user?.id}/>}
          </div>
        </div>

        {viewing && <Modal t={viewing} openPrices={openPrices} onClose={()=>setViewing(null)}/>}

        {/* Mobile bottom nav */}
        <nav className="mobile-nav">
          {[
            {p:"dashboard",icon:"📊",label:"Dashboard"},
            {p:"journal",icon:"📓",label:"Journal"},
            {p:"add",icon:"➕",label:"New Trade"},
            {p:"calendar",icon:"📅",label:"Calendar"},
            {p:"goals",icon:"🎯",label:"Goals"},
            {p:"stickies",icon:"📌",label:"Notes"},
            {p:"alerts",icon:"🔔",label:"Alerts"},
          ].map(({p,icon,label})=>(
            <button key={p} className={page===p?"active":""} onClick={()=>setPage(p)}>
              <span className="icon">{icon}</span>{label}
            </button>
          ))}
          <button onClick={toggleTheme} style={{background:'none',border:'none',color:'var(--txt3)',fontSize:10,cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:3,padding:'4px 12px',minWidth:56}}>
            <span className="icon">{theme==='dark'?'☀':'🌙'}</span>{theme==='dark'?'Light':'Dark'}
          </button>
        </nav>

        {/* Toast notification */}
        {toast && (
          <div style={{position:"fixed",bottom:24,right:24,background:"var(--bg4)",border:"1px solid var(--border2)",borderRadius:10,padding:"10px 18px",fontSize:13,color:"var(--txt1)",zIndex:9999,fontFamily:"'DM Mono'",boxShadow:"0 8px 32px rgba(0,0,0,.5)",animation:"slideUp .25s ease"}}>
            {toast}
          </div>
        )}
      </>
    )}
  </>;
}

